class Solution {
public:
    vector<int> twoSum(vector<int>& nums, int target) {
        unordered_map<int,int> mpp;
        int n = nums.size();
        vector<int> ans;
        for(int i = 0;i<n;i++) mpp[nums[i]] = i;

        for(int i = 0;i<n;i++){
            int diff = (target-nums[i]);
            if(mpp.count(diff)){
                cout<<2<<endl;
                if(mpp[diff] != i){
                    ans = {mpp[diff],i};
                break;
                }
            }

        }
        return ans;
    }
};
